79	/** Insert `text` at a position, cursor at its end — for Enter-on-heading
80	 * and Shift+Enter, which are text-level (transient-state) edits. */
81	function insertionPlan(
82	  lines: readonly string[],
83	  at: EditorPos,
84	  text: string,
85	  userEvent: string,
86	): GrammarOutcome {
87	  const before = (lines[at.line] ?? '').slice(0, at.ch);
88	  const changes: EditorChange[] = [{ from: at, to: at, text }];
89	  const inserted = text.split('\n');
90	  const newCursorLine = at.line + inserted.length - 1;
91	  const newCh =
92	    inserted.length === 1 ? before.length + text.length : (inserted.at(-1) ?? '').length;
93	  // Build enough of the new text to compute the offset.
94	  const newLines = [...lines];
95	  const tail = (lines[at.line] ?? '').slice(at.ch);
96	  newLines.splice(
97	    at.line,
98	    1,
99	    before + inserted[0]!,
100	    ...inserted.slice(1, -1),
101	    ...(inserted.length > 1 ? [(inserted.at(-1) ?? '') + tail] : []),
102	  );
103	  if (inserted.length === 1) newLines[at.line] = before + text + tail;
104	  return {
105	    plan: {
106	      changes,
107	      selection: offsetInNewText(newLines, { line: newCursorLine, ch: newCh }),
108	      userEvent,
109	    },
110	  };
111	}
112	
113	export function planKey(text: string, cursor: EditorPos, key: GrammarKey): GrammarOutcome {
114	  const doc = parse(text);
115	  const node = nodeAtLine(doc, cursor.line);
116	  if (!node) return null; // preamble or nothing: stock behavior
117	  const lines = text === '' ? [] : text.split('\n');
118	  const nodeStart = startLine(doc, node);
119	  const onFirstLine = cursor.line === nodeStart;
120	  const onOwnLines = cursor.line < nodeStart + node.lines.length;
121	
122	  // Atom interiors are opaque: only whole-atom ops from the first line.
123	  if (isAtom(node)) {
124	    if (!onFirstLine) return null;
125	    if (key === 'split' || key === 'continue') return null;
126	  }
127	  // Cursor on a gap line: structural ops act on the owning node; text-level
128	  // keys behave stock.
129	  if (!onOwnLines && (key === 'split' || key === 'continue')) return null;
130	
131	  switch (key) {
132	    case 'indent':
133	      return planFromOp(lines, indent(doc, node.id), 'input.structure.indent');
134	    case 'outdent':
135	      return planFromOp(lines, outdent(doc, node.id), 'input.structure.outdent');
136	    case 'move-up':
137	      return planFromOp(lines, moveUp(doc, node.id), 'move.structure');
138	    case 'move-down':
139	      return planFromOp(lines, moveDown(doc, node.id), 'move.structure');
140	    case 'split': {
141	      if (node.kind === 'heading') {
142	        // Enter on a heading: empty paragraph child right below the line.
143	        const line = lines[cursor.line] ?? '';
144	        return insertionPlan(
145	          lines,
146	          { line: cursor.line, ch: line.length },
147	          '\n',
148	          'input.structure.split',
149	        );
150	      }
151	      return planFromOp(
152	        lines,
153	        splitNode(doc, node.id, cursor),
154	        'input.structure.split',
155	      );
156	    }
157	    case 'continue': {
158	      if (node.kind === 'list-item' && onFirstLine) {
159	        const match = LIST_CONT_RE.exec(node.lines[0] ?? '');
160	        const prefix = match ? `${match[1]}${' '.repeat(match[2]!.length + match[3]!.length)}` : '';
161	        return insertionPlan(lines, cursor, `\n${prefix}`, 'input');
162	      }
163	      if (node.kind === 'list-item') {
164	        // Continuation line: keep its own leading whitespace.
165	        const ws = /^[ \t]*/.exec(lines[cursor.line] ?? '')?.[0] ?? '';
166	        return insertionPlan(lines, cursor, `\n${ws}`, 'input');
167	      }
168	      return insertionPlan(lines, cursor, '\n', 'input');
169	    }
170	  }
171	}
